mapper.select:
/* 유효한 공유 토큰 → ROOM_ID (만료되지 않은 경우만) ai.chatbot.selectShareTokenValidRoomId */
SELECT T.ROOM_ID AS roomId
FROM TB_SHARE_TOKEN T
WHERE T.SHARE_TOKEN = #{shareToken}
  AND T.EXPIRED_DT > NOW()

/* 공유 토큰 존재 여부 (만료 여부 판별용) ai.chatbot.countShareTokenByToken */
SELECT COUNT(1)
FROM TB_SHARE_TOKEN T
WHERE T.SHARE_TOKEN = #{shareToken}

mapper.update:
/* CHAT 대화방 마지막 채팅 일시 업데이트 ai.chatbot.updateChatRoomLastChatDt */
UPDATE TB_CHAT_ROOM
SET LAST_CHAT_DT = NOW()
WHERE ROOM_ID = #{roomId}

/* CHAT 대화방 만족도 조회 ai.chatbot.selectSatisYn */
UPDATE TB_CHAT_LOG
SET SATIS_YN = #{satisYn}
    , SATIS_CONTENT = #{satisContent}
    , SATIS_DT = NOW()
WHERE LOG_ID = #{logId}

/* 채팅방 고정 ai.chatbot.updatePinChatRoom */
UPDATE TB_CHAT_ROOM
SET FIX_YN = CASE WHEN FIX_YN = 'Y' THEN 'N' ELSE 'Y' END
WHERE ROOM_ID = #{roomId}

/* 채팅방 제목 수정 ai.chatbot.updateChatRoomTitle */
UPDATE TB_CHAT_ROOM
SET ROOM_TITLE = #{roomTitle}
WHERE ROOM_ID = #{roomId}

mapper.delete:
/* 채팅방 삭제 ai.chatbot.deleteChatRoom */
DELETE FROM TB_CHAT_ROOM
WHERE ROOM_ID = #{roomId}

mapper.select:
/* 지식 카드 최대 정렬 순서 조회 ai.chatbot.selectMaxSortOrd */
SELECT IFNULL(MAX(A.SORT_ORD), 0)
FROM TB_KNOW_CARD A
WHERE A.USER_ID = #{userId}
  AND A.CATEGORY_ID = #{categoryId}
